import{_ as t,o as i,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"16B. Climate Change Mitigation And Sustainability","description":"","frontmatter":{"title":"16B. Climate Change Mitigation And Sustainability","eba":"Nurses and Midwives 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/16B-climate-change-mitigation-and-sustainability.md","filePath":"ebas/nurses-midwives/consultation-disputes/16B-climate-change-mitigation-and-sustainability.md"}'),s={name:"ebas/nurses-midwives/consultation-disputes/16B-climate-change-mitigation-and-sustainability.md"};function o(r,e,l,p,g,c){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_16b-climate-change-mitigation-and-sustainability" tabindex="-1">16B. Climate Change Mitigation And Sustainability <a class="header-anchor" href="#_16b-climate-change-mitigation-and-sustainability" aria-label="Permalink to &quot;16B. Climate Change Mitigation And Sustainability&quot;">​</a></h1><p><strong>16B.1</strong> Acknowledgment</p><p>The parties acknowledge that:</p><p><strong>(a)</strong> the climate is changing and this affects the health and wellbeing of Victorians:</p><p><strong>(b)</strong> Health Services use significant amounts of energy and water and generate large volumes of waste;</p><p><strong>(c)</strong> the Climate Change Act 2017 has a long-term emissions reduction target for Victoria of net zero greenhouse gas emissions by the year 2050 with a series of interim targets to achieve that goal, and the Victorian Government has announced a revised target of 2045 for net zero; and</p><p><strong>(d)</strong> Employees and Health Services have a role to play to support the achievement of that target, which includes through discussion, information sharing and cooperation.</p><p><strong>16B.2</strong> Continuous improvement</p><p><strong>(a)</strong> Employees and Employers support continuous improvement to improve environmental sustainability including:</p><p><strong>(i)</strong> At an industry level through the Central Implementation Committee at <a href="/eba/ebas/nurses-midwives/union-matters/80-union-matters.html">clause 80.11</a>;</p><p><strong>(ii)</strong> At a local workplace level through:</p><p><strong>(A)</strong> the WIC; and/or</p><p><strong>(B)</strong> a local body established for the purpose of consulting over environmental sustainability and climate change (however described).</p><p><strong>(b)</strong> Employers and Employees support the development of local processes to:</p><p><strong>(i)</strong> integrate climate and environmental considerations into the evidence based decision-making process;</p><p><strong>(ii)</strong> engage with Employees and other health service employees to consult over matters of environmental sustainability including possible mitigants such as:</p><p><strong>(A)</strong> recycling and waste reduction;</p><p><strong>(B)</strong> better use of technology;</p><p><strong>(C)</strong> healthy sustainable buildings, infrastructure and materials; and</p><p><strong>(D)</strong> the delivery of health services,</p><p><strong>(iii)</strong> implement change at the workplace level to achieve environmental sustainability objectives including through local action plans as Health Services seek to move to 100% renewable energy by 2025.</p><p><strong>16B.3</strong> Education</p><p><strong>(a)</strong> It is acknowledged that education concerning climate related health topics may be directly relevant to an Employee’s role within the meaning of <a href="/eba/ebas/nurses-midwives/education-pd/75-professional-development-leave.html">clause 75</a> (Professional Development Leave).</p><p><strong>(b)</strong> The Employer will encourage and support the inclusion of climate-related health topics as part of education provided to Employees.</p><p><strong>16B.4</strong> Introduction of Sustainability Nurse/Midwife Representative (SNR/SMR)</p><p><strong>(a)</strong> Each Employer will actively encourage up to two interested Employees per ward or unit to become a Sustainability Nurse/Midwife Representatives.</p><p><strong>(b)</strong> Where the Sustainability Nurse/Midwife Representative requests time release to participate in sustainability activities in the ward / unit or Employer, such time release will not be unreasonably refused.</p><p><strong>16B.5</strong> Discussions with ANMF</p><p>Upon request, a Health Service will meet a representative of the ANMF to discuss the sustainability report of the Health Service.</p>',29)])])}const u=t(s,[["render",o]]);export{d as __pageData,u as default};
